/**
 * Organism Repair CLI — scan, diagnose, plan, project, fix.
 *
 * Usage:
 *   npx tsx src/dogfood-repair.ts [project-path] [--dry-run|--fix] [--limit N]
 *
 * --dry-run (default): scan → diagnose → project health after each fix
 * --fix: actually apply the patches, then re-scan to verify
 */

import { resolve, relative, extname, join } from 'path';
import { readdirSync } from 'fs';
import { analyzePolyglotSource } from './polyglot-bridge';
import type { PolyglotAnalysisResult } from './polyglot-bridge';
import {
  diagnoseProject,
  computePurityProfile,
  type ProjectCheckpointProfile,
} from './polyglot-checkpoint-bridge';
import {
  generateRepairPlan,
  applyRepairPlan,
  type RepairPlan,
  type RepairPatch,
} from './organism-repair';
import { diagnose, forecastRepair } from './checkpoint-substrates';

// ── Args ───────────────────────────────────────────────────────────

const args = process.argv.slice(2);
const projectPath = args.find(a => !a.startsWith('--'))
  ? resolve(args.find(a => !a.startsWith('--'))!)
  : resolve(import.meta.dirname, '..');
const mode = args.includes('--fix') ? 'fix' : 'dry-run';
const limitArg = args.find(a => a.startsWith('--limit'));
const limit = limitArg ? parseInt(limitArg.split('=')[1] ?? args[args.indexOf(limitArg) + 1] ?? '10', 10) : 10;
const sampleSize = parseInt(
  args.find(a => a.startsWith('--sample'))?.split('=')[1] ?? '50',
  10,
);

const ROOT = resolve(projectPath, '..', '..');
const projectName = relative(ROOT, projectPath) || projectPath;

console.log(`\nOrganism Repair: ${projectName}`);
console.log(`Mode: ${mode} | Limit: ${limit} patches | Sample: ${sampleSize} files`);
console.log('='.repeat(70));

// ── File discovery ─────────────────────────────────────────────────

const IGNORED_DIRS = new Set([
  'node_modules', '.next', 'dist', 'build', '.git', 'coverage',
  '.wrangler', '__tests__', '.a0', '.gnosis', '.lake', '.tmp',
  'target', '.turbo',
]);
const SCANNABLE = new Set(['.ts', '.tsx', '.js', '.jsx']);

function walkSourceFiles(root: string): string[] {
  const files: string[] = [];
  const queue = [root];
  while (queue.length > 0) {
    const dir = queue.pop()!;
    let entries;
    try { entries = readdirSync(dir, { withFileTypes: true }); } catch { continue; }
    for (const entry of entries) {
      if (entry.isDirectory()) {
        if (!IGNORED_DIRS.has(entry.name)) queue.push(join(dir, entry.name));
      } else if (SCANNABLE.has(extname(entry.name))) {
        files.push(join(dir, entry.name));
      }
    }
  }
  return files;
}

// ── Phase 1: Scan ──────────────────────────────────────────────────

console.log('\n[1/4] Scanning...');
const allFiles = walkSourceFiles(resolve(projectPath, 'src'));
const sample = allFiles.slice(0, sampleSize);

const fileResults: Array<{ filePath: string; result: PolyglotAnalysisResult }> = [];
for (const filePath of sample) {
  try {
    const result = await analyzePolyglotSource(filePath);
    fileResults.push({ filePath, result });
  } catch { /* skip */ }
}
console.log(`  Scanned ${fileResults.length} files`);

// ── Phase 2: Diagnose ──────────────────────────────────────────────

console.log('\n[2/4] Diagnosing...');
const profile = diagnoseProject(projectName, fileResults);
const pp = profile.purityProfile;

console.log(`  Functions:     ${profile.scan.functionCount}`);
console.log(`  Active:        ${profile.activeChannels} (${(profile.activeChannels / Math.max(1, profile.scan.functionCount) * 100).toFixed(1)}%)`);
console.log(`  Destroyed:     ${profile.destroyedChannels}`);
console.log(`  Raw sigma:     ${profile.sigma.toFixed(4)}`);
console.log(`  Raw health:    ${profile.diagnosis.health}`);
console.log(`  Purity:        ${(pp.purityRatio * 100).toFixed(1)}% pure | baseline=${pp.purityBaseline.toFixed(3)}`);
console.log(`  Adj sigma:     ${pp.adjustedSigma.toFixed(4)}`);
console.log(`  Adj health:    ${pp.adjustedHealth}`);

// ── Phase 3: Plan + Project ────────────────────────────────────────

console.log('\n[3/4] Planning repairs...');
const plan = generateRepairPlan(fileResults, projectPath, limit);

console.log(`  Deaf branching functions: ${plan.totalDeafBranching}`);
console.log(`  Patches generated: ${plan.patchCount}`);

if (plan.patches.length === 0) {
  console.log('\n  No patches to generate — all branching functions already have VENT paths.');
  process.exit(0);
}

// Project health improvement step by step (God Formula sequencing)
console.log('\n  PROJECTED HEALTH TRAJECTORY:');
console.log('  ' + '-'.repeat(66));
console.log(
  '  Step'.padEnd(8) +
  'Function'.padEnd(35) +
  'Adj σ'.padStart(8) +
  'Health'.padStart(12) +
  'Δ'.padStart(8)
);
console.log('  ' + '-'.repeat(66));

// Start from current state
let simulatedActive = profile.activeChannels;
let simulatedDestroyed = profile.destroyedChannels;

// Show current state
const currentTotal = simulatedActive + simulatedDestroyed;
const currentSigma = currentTotal > 0 ? simulatedDestroyed / currentTotal : 0;
const currentAdj = Math.max(0, currentSigma - pp.purityBaseline);
console.log(
  '  now'.padEnd(8) +
  '(current state)'.padEnd(35) +
  currentAdj.toFixed(4).padStart(8) +
  pp.adjustedHealth.padStart(12) +
  ''.padStart(8)
);

// Simulate applying each patch in sequence
for (let i = 0; i < plan.patches.length; i++) {
  const patch = plan.patches[i];

  // Each patch converts one deaf branching function to active
  simulatedActive += 1;
  simulatedDestroyed -= 1;

  const newTotal = simulatedActive + simulatedDestroyed;
  const newSigma = newTotal > 0 ? simulatedDestroyed / newTotal : 0;
  const newAdj = Math.max(0, newSigma - pp.purityBaseline);

  // Classify health
  let health: string;
  if (newAdj >= 1.0) health = 'necrotic';
  else if (newAdj >= 0.6) health = 'cancerous';
  else if (newAdj >= 0.3) health = 'inflamed';
  else if (newAdj >= 0.1) health = 'stressed';
  else health = 'healthy';

  const delta = newAdj - currentAdj;
  const deltaStr = delta < 0 ? delta.toFixed(4) : '+' + delta.toFixed(4);

  console.log(
    `  #${i + 1}`.padEnd(8) +
    patch.functionName.slice(0, 34).padEnd(35) +
    newAdj.toFixed(4).padStart(8) +
    health.padStart(12) +
    deltaStr.padStart(8)
  );
}

// Final projected state
const finalTotal = simulatedActive + simulatedDestroyed;
const finalSigma = finalTotal > 0 ? simulatedDestroyed / finalTotal : 0;
const finalAdj = Math.max(0, finalSigma - pp.purityBaseline);
let finalHealth: string;
if (finalAdj >= 1.0) finalHealth = 'necrotic';
else if (finalAdj >= 0.6) finalHealth = 'cancerous';
else if (finalAdj >= 0.3) finalHealth = 'inflamed';
else if (finalAdj >= 0.1) finalHealth = 'stressed';
else finalHealth = 'healthy';

console.log('  ' + '-'.repeat(66));
console.log(
  '  done'.padEnd(8) +
  `(after ${plan.patchCount} patches)`.padEnd(35) +
  finalAdj.toFixed(4).padStart(8) +
  finalHealth.padStart(12) +
  (finalAdj - currentAdj).toFixed(4).padStart(8)
);

// ── Phase 4: Apply or Show ─────────────────────────────────────────

if (mode === 'fix') {
  console.log('\n[4/4] Applying patches...');
  const result = applyRepairPlan(plan);
  console.log(`  Applied: ${result.applied}`);
  console.log(`  Skipped: ${result.skipped}`);
  if (result.errors.length > 0) {
    console.log(`  Errors:`);
    for (const e of result.errors) console.log(`    ${e}`);
  }

  // Re-scan to verify improvement
  if (result.applied > 0) {
    console.log('\n  Re-scanning to verify...');
    const reFileResults: Array<{ filePath: string; result: PolyglotAnalysisResult }> = [];
    for (const filePath of sample) {
      try {
        const r = await analyzePolyglotSource(filePath);
        reFileResults.push({ filePath, result: r });
      } catch { /* skip */ }
    }
    const reProfile = diagnoseProject(projectName + ' (after fix)', reFileResults);
    const rePP = reProfile.purityProfile;

    console.log(`\n  AFTER FIX:`);
    console.log(`    Active:      ${reProfile.activeChannels}`);
    console.log(`    Destroyed:   ${reProfile.destroyedChannels}`);
    console.log(`    Raw sigma:   ${reProfile.sigma.toFixed(4)}`);
    console.log(`    Adj sigma:   ${rePP.adjustedSigma.toFixed(4)}`);
    console.log(`    Adj health:  ${rePP.adjustedHealth}`);
  }
} else {
  console.log('\n[4/4] Dry run complete. Run with --fix to apply patches.');

  // Show the patches
  console.log('\nPATCH DETAILS:');
  for (let i = 0; i < plan.patches.length; i++) {
    const p = plan.patches[i];
    const rel = relative(projectPath, p.filePath);
    console.log(`\n--- Patch ${i + 1}/${plan.patchCount}: ${p.functionName} ---`);
    console.log(`File: ${rel}:${p.startLine}-${p.endLine}`);
    console.log(`Buley: ${p.buleyMeasure.toFixed(1)} | ${p.description}`);
    const origFirst3 = p.originalSource.split('\n').slice(0, 3);
    const patchFirst5 = p.patchedSource.split('\n').slice(0, 5);
    console.log(`Before:`);
    for (const l of origFirst3) console.log(`  ${l}`);
    console.log(`  ...`);
    console.log(`After:`);
    for (const l of patchFirst5) console.log(`  ${l}`);
    console.log(`  ...`);
  }
}
